-- ============================================================
-- KP AMS — Data Restoration (Apex, Zenith, Nova, Sterling, Meridian)
-- ============================================================

-- 1. Restore Clients
ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, gstn = EXCLUDED.gstn, status = EXCLUDED.status;

-- 2. Restore Proposals
ON CONFLICT (id) DO UPDATE SET status = EXCLUDED.status;

-- 3. Restore Assignments with Billed Amount and Amount Receipt
ON CONFLICT (id) DO UPDATE SET billed_amount = EXCLUDED.billed_amount, amount_receipt = EXCLUDED.amount_receipt;

-- 4. Restore Fee Allocations
-- Simplified for restoration
ON CONFLICT DO NOTHING;
